'use client';

import React from 'react';

// Real logo images, embedded directly as base64 so nothing needs to be
// placed in /public or referenced by a separate file path, this file is
// fully self-contained. Uploaded directly by the project owner, not
// fetched from any external source, so nothing can break or rate-limit.
const KNOWN_LOGO_DATA_URIS: Record<string, string> = {
  USDC: 'data:image/png;base64,',
  USDT: 'data:image/png;base64,',
  WETH: 'data:image/png;base64,',
  ZAMA: 'data:image/webp;base64,',
  XAUT: 'data:image/png;base64,',
  BRON: 'data:image/webp;base64,',
  TGBP: 'data:image/webp;base64,',
  STEAKUSDC: 'data:image/webp;base64,',
};

const KNOWN_TOKEN_COLORS: Record<string, { bg: string; text: string }> = {
  USDC: { bg: '#2775CA', text: '#FFFFFF' },
  USDT: { bg: '#26A17B', text: '#FFFFFF' },
  WETH: { bg: '#627EEA', text: '#FFFFFF' },
  ETH:  { bg: '#627EEA', text: '#FFFFFF' },
  ZAMA: { bg: '#FFD208', text: '#000000' }, // Zama brand: black on yellow
  XAUT: { bg: '#C9A227', text: '#000000' }, // Tether Gold, gold tone
  BRON: { bg: '#52525B', text: '#FFFFFF' },
  TGBP: { bg: '#3B5BDB', text: '#FFFFFF' },
  STEAKUSDC: { bg: '#0EA5A5', text: '#FFFFFF' },
};

function fallbackColor(symbol: string): { bg: string; text: string } {
  let hash = 0;
  for (let i = 0; i < symbol.length; i++) {
    hash = symbol.charCodeAt(i) + ((hash << 5) - hash);
  }
  const hue = Math.abs(hash) % 360;
  return { bg: `hsl(${hue}, 55%, 42%)`, text: '#FFFFFF' };
}

export function TokenIcon({
  symbol,
  size = 36,
  className = '',
}: {
  symbol: string;
  size?: number;
  className?: string;
}) {
  const key = (symbol || '?').toUpperCase().replace(/[^A-Z0-9]/g, '');

  // Exact match first. If the live on-chain symbol differs slightly from
  // what was assumed (extra characters, a prefix, a suffix), fall back to
  // checking whether a known key appears inside it, longest key first so
  // e.g. STEAKUSDC is checked before USDC and doesn't get misidentified.
  let dataUri = KNOWN_LOGO_DATA_URIS[key];
  if (!dataUri) {
    const sortedKeys = Object.keys(KNOWN_LOGO_DATA_URIS).sort((a, b) => b.length - a.length);
    const matchedKey = sortedKeys.find((k) => key.includes(k));
    if (matchedKey) dataUri = KNOWN_LOGO_DATA_URIS[matchedKey];
  }

  if (dataUri) {
    return (
      // eslint-disable-next-line @next/next/no-img-element
      <img
        src={dataUri}
        alt={symbol}
        title={symbol}
        width={size}
        height={size}
        className={`rounded-full shrink-0 object-cover ${className}`}
      />
    );
  }

  let colors = KNOWN_TOKEN_COLORS[key];
  if (!colors) {
    const sortedColorKeys = Object.keys(KNOWN_TOKEN_COLORS).sort((a, b) => b.length - a.length);
    const matchedColorKey = sortedColorKeys.find((k) => key.includes(k));
    colors = matchedColorKey ? KNOWN_TOKEN_COLORS[matchedColorKey] : fallbackColor(key);
  }
  return (
    <div
      className={`flex items-center justify-center rounded-full font-bold shrink-0 ${className}`}
      style={{
        width: size,
        height: size,
        backgroundColor: colors.bg,
        color: colors.text,
        fontSize: Math.max(10, Math.round(size * 0.4)),
      }}
      title={symbol}
    >
      {key.charAt(0)}
    </div>
  );
}
